CREATE TABLE IF NOT EXISTS users(id INT AUTO_INCREMENT PRIMARY KEY, username VARCHAR(80) UNIQUE NOT NULL, password_hash VARCHAR(255) NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS settings(name VARCHAR(80) PRIMARY KEY, value TEXT) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS animals(id INT AUTO_INCREMENT PRIMARY KEY, title VARCHAR(160) NOT NULL, slug VARCHAR(180) UNIQUE NOT NULL, description TEXT, cover_image VARCHAR(255), layout VARCHAR(30) DEFAULT 'masonry', published TINYINT DEFAULT 1, sort_order INT DEFAULT 0, meta_title VARCHAR(160), meta_description VARCHAR(300), blocks LONGTEXT, views INT DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS photos(id INT AUTO_INCREMENT PRIMARY KEY, animal_id INT NOT NULL, image_path VARCHAR(255) NOT NULL, title VARCHAR(160), caption TEXT, sort_order INT DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, INDEX(animal_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS posts(id INT AUTO_INCREMENT PRIMARY KEY, title VARCHAR(160) NOT NULL, slug VARCHAR(180) UNIQUE NOT NULL, excerpt TEXT, content TEXT, cover_image VARCHAR(255), published TINYINT DEFAULT 1, meta_title VARCHAR(160), meta_description VARCHAR(300), blocks LONGTEXT, views INT DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS albums(id INT AUTO_INCREMENT PRIMARY KEY, title VARCHAR(160) NOT NULL, slug VARCHAR(180) UNIQUE NOT NULL, description TEXT, cover_image VARCHAR(255), layout VARCHAR(30) DEFAULT 'masonry', published TINYINT DEFAULT 1, sort_order INT DEFAULT 0, meta_title VARCHAR(160), meta_description VARCHAR(300), blocks LONGTEXT, views INT DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS album_photos(id INT AUTO_INCREMENT PRIMARY KEY, album_id INT NOT NULL, image_path VARCHAR(255) NOT NULL, title VARCHAR(160), caption TEXT, sort_order INT DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, INDEX(album_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS messages(id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(160), email VARCHAR(160), message TEXT, is_read TINYINT DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- Pagebuilder: eigen pagina's met blokken opgeslagen als JSON-tekst.
-- LONGTEXT ipv het MySQL-native JSON-type voor maximale compatibiliteit met
-- goedkope/gedeelde hosting (bv. oudere MySQL-versies op InfinityFree).
CREATE TABLE IF NOT EXISTS pages(id INT AUTO_INCREMENT PRIMARY KEY, title VARCHAR(160) NOT NULL, slug VARCHAR(180) UNIQUE NOT NULL, blocks LONGTEXT, published TINYINT DEFAULT 0, show_in_nav TINYINT DEFAULT 0, is_homepage TINYINT DEFAULT 0, meta_title VARCHAR(160), meta_description VARCHAR(300), sort_order INT DEFAULT 0, views INT DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

